  "aura-form": AuraBaseAttributes;
  "aura-grid": AuraGridAttributes;
  "aura-icon": AuraIconAttributes;
  "aura-image": AuraImageAttributes;
  "aura-link": AuraLinkAttributes;
  "aura-menu": AuraBaseAttributes;
  "aura-menu-item": AuraMenuItemAttributes;
  "aura-nav-group": AuraNavGroupAttributes;
  "aura-nav-header": AuraBaseAttributes;
  "aura-nav-item": AuraNavItemAttributes;
  "aura-nav-menu": AuraNavMenuAttributes;
  "aura-option": AuraOptionAttributes;
  "aura-option-group": AuraOptionGroupAttributes;
  "aura-pagination": AuraPaginationAttributes;
  "aura-panel": AuraPanelAttributes;
  "aura-progress": AuraProgressAttributes;
  "aura-radio": AuraRadioAttributes;
  "aura-range": AuraRangeAttributes;
  "aura-row": AuraRowAttributes;
  "aura-select": AuraSelectAttributes;
  "aura-spacer": AuraBaseAttributes;
  "aura-sparkline": AuraSparklineAttributes;
  "aura-split": AuraSplitAttributes;
  "aura-stack": AuraStackAttributes;
  "aura-stepper": AuraStepperAttributes;
  "aura-steps": AuraStepsAttributes;
