/* --------------------------------------------------------------------------
 * Custom-event detail payloads (from the actual dispatch sites in js/) —
 * the SAME table the React binding emits, so the Svelte `events` action is
 * typed identically to React's event map (#612).
 * ----------------------------------------------------------------------- */

/** Detail for `aura:change` — the shared value-change event. Which fields are present depends on the dispatching element. */
export interface AuraChangeDetail {
  /** New value (select / range / pickers / stepper / color / checkbox / radio). */
  value?: string;
  /** Display label of the selection (select / datepicker). */
  label?: string;
  /** New checked state (aura-switch / aura-checkbox / aura-radio). */
  checked?: boolean;
  /** Post-toggle mixed state (aura-checkbox / aura-radio). */
  indeterminate?: boolean;
  /** Current tag list (aura-tag-input). */
  tags?: string[];
  /** Panel ratios after a resize (aura-split). */
  ratios?: number[];
  /** Selected date (aura-datepicker). */
  date?: Date | null;
  /** Range start (datepicker / timepicker range mode). */
  start?: string | Date | null;
  /** Range end (datepicker / timepicker range mode). */
  end?: string | Date | null;
  /** Both range ends committed (datepicker / timepicker range mode). */
  complete?: boolean;
  /** True for multi-select change events (aura-select). */
  multiple?: boolean;
  /** RGB triple from aura-color-picker (r/g/b each 0–255). */
  rgb?: { r: number; g: number; b: number };
  /** HSL triple from aura-color-picker (h: 0–360, s/l: 0–100). */
  hsl?: { h: number; s: number; l: number };
  /** OKLCH triple from aura-color-picker (l: 0–1, c: 0–0.4, h: 0–360). */
  oklch?: { l: number; c: number; h: number };
  /** Alpha channel 0–1 (aura-color-picker). */
  alpha?: number;
  /** Current content as HTML (aura-editor). */
  html?: string;
  /** Current content as plain text (aura-editor). */
  text?: string;
}

/** Detail for `aura:copy` (copy-to-clipboard affordances, aura-code). */
export interface AuraCopyDetail {
  /** The text that was copied to the clipboard. */
  text: string;
}

/** Detail for `aura:dialog-close`. */
export interface AuraDialogCloseDetail {
  /** The dialog element that closed. */
  dialog: HTMLElement;
}

/** Detail for `aura:dialog-open`. */
export interface AuraDialogOpenDetail {
  /** The dialog element that opened. */
  dialog: HTMLElement;
  /** The element that triggered the open (null when opened programmatically). */
  opener: HTMLElement | null;
}

/** Detail for `aura:footer-revealed` (aura-footer intersection reveal/conceal). */
export interface AuraFooterRevealedDetail {
  /** True when the footer enters the viewport; false when it leaves. */
  revealed: boolean;
}

/** Detail for `aura:form-change` (aura-form dependent-field engine). */
export interface AuraFormChangeDetail {
  /** Number of managed fields after the change. */
  managed: number;
}

/** Detail for `aura:menu-select` (context/dropdown menus). */
export interface AuraMenuSelectDetail {
  /** The item's value attribute (falls back to its label). */
  value: string;
  /** The item's visible label text. */
  label: string;
  /** Checked state for checkable items (always present; false when not checkable). */
  checked: boolean;
  /** The selected menu item element. */
  item: HTMLElement;
  /** The item's data-aura-action, if any. */
  action: string | null;
}

/** Detail for `aura:nav-panel-open` (aura-nav-header dropdown panels). */
export interface AuraNavPanelOpenDetail {
  /** The trigger button that opened the panel. */
  trigger: HTMLElement;
}

/** Detail for `aura:tab-change` (aura-tabs). */
export interface AuraTabChangeDetail {
  /** The newly-selected tab. */
  tab: HTMLElement;
  /** The previously-selected tab (null on initial sync). */
  previous: HTMLElement | null;
}

/**
 * Typed map of every Aura custom event NAME → event object, generated from
 * the literal `new CustomEvent(…)` dispatch sites in js/ — the Svelte
 * analogue of the React `AuraEventMap` (#612). Extend via declaration
 * merging to add your own events.
 */
export interface AuraEventMap {
  "aura:change": CustomEvent<AuraChangeDetail>;
  "aura:copy": CustomEvent<AuraCopyDetail>;
  "aura:dialog-close": CustomEvent<AuraDialogCloseDetail>;
  "aura:dialog-open": CustomEvent<AuraDialogOpenDetail>;
  "aura:dirty": CustomEvent<undefined>;
  "aura:footer-revealed": CustomEvent<AuraFooterRevealedDetail>;
  "aura:form-change": CustomEvent<AuraFormChangeDetail>;
  "aura:menu-select": CustomEvent<AuraMenuSelectDetail>;
  "aura:nav-panel-open": CustomEvent<AuraNavPanelOpenDetail>;
  "aura:tab-change": CustomEvent<AuraTabChangeDetail>;
}

/** A map of `{ eventName: handler }` for the `events` action. Keyed by the
 *  known Aura event names with typed `CustomEvent<…Detail>` payloads (so
 *  `e.detail` narrows without a cast and a typo'd name is rejected), plus
 *  an escape hatch for consumer-dispatched / future event names (#612).
 *  Aura's colon-named custom events (e.g. `aura:change`) are not
 *  expressible as Svelte `on*` props, so this action is the canonical
 *  Svelte 5 path for them. */
export type AuraEventActionMap = {
  [K in keyof AuraEventMap]?: (event: AuraEventMap[K]) => void;
} & {
  /** Consumer-dispatched / future events: any other name is accepted. */
  [eventName: string]: ((event: CustomEvent) => void) | undefined;
};

/** Union of all built-in Aura event names — `keyof AuraEventMap`. */
export type AuraEventName = keyof AuraEventMap;

/**
 * Svelte action: attach a map of custom-event handlers to a node,
 * updating reactively and cleaning up on destroy.
 *
 * @example
 * ```svelte
 * <script>
 *   import { events } from "@aura-design/core/bindings/svelte";
 *   let value = $state("");
 * </script>
 *
 * <aura-select use:events={{ "aura:change": (e) => { value = e.detail.value; } }}>
 *   <aura-option value="a">Option A</aura-option>
 *   <aura-option value="b">Option B</aura-option>
 * </aura-select>
 * <p>Selected: {value}</p>
 * ```
 */
export declare function events(
  node: HTMLElement,
  map: AuraEventActionMap
): { update(next: AuraEventActionMap): void; destroy(): void };

/** The public custom-element tag names Aura registers (generated). */
export declare const AURA_TAGS: readonly string[];

/** Compiler predicate: every `aura-*` tag is a custom element. */
export declare function isAuraElement(tag: unknown): boolean;

/* Svelte template typing (Svelte 5): svelteHTML.IntrinsicElements maps
   each aura-* tag to its attribute interface, so attributes are checked
   and typos error. Ambient — activates when Svelte's types are present. */
declare global {
  namespace svelteHTML {
    interface IntrinsicElements extends AuraElements {}
  }
}

export {};
